import{_ as a,o as r,c as i,a2 as t}from"./chunks/framework.B36PHH5O.js";const p=JSON.parse('{"title":"S3 For XunRuiCMS","description":"","frontmatter":{},"headers":[],"relativePath":"zh-Hant/about.md","filePath":"zh-Hant/about.md","lastUpdated":1778063279000}'),l={name:"zh-Hant/about.md"};function o(n,e,h,s,u,c){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="s3-for-xunruicms" tabindex="-1">S3 For XunRuiCMS <a class="header-anchor" href="#s3-for-xunruicms" aria-label="Permalink to &quot;S3 For XunRuiCMS&quot;">​</a></h1><h2 id="將項目標複" tabindex="-1">將項目標複 <a class="header-anchor" href="#將項目標複" aria-label="Permalink to &quot;將項目標複&quot;">​</a></h2><p>S3 For XunRuiCMS 是一個支援迅睿CMS系統使用 AWS S3 云存储的插件。</p><h2 id="程式特性" tabindex="-1">程式特性 <a class="header-anchor" href="#程式特性" aria-label="Permalink to &quot;程式特性&quot;">​</a></h2><ul><li>完整的文件上傳/下載管理功能</li><li>支援大文件分片上傳和斷點續傳</li><li>无缝集成到迅睿CMS文件管理系统</li><li>完善的錯誤處理和日誌記錄</li></ul><h2 id="設置需求" tabindex="-1">設置需求 <a class="header-anchor" href="#設置需求" aria-label="Permalink to &quot;設置需求&quot;">​</a></h2><ul><li><p>PHP 7.4 或更高版本</p></li><li><p>迅睿CMS 5.0+</p></li></ul><h2 id="安裝方式" tabindex="-1">安裝方式 <a class="header-anchor" href="#安裝方式" aria-label="Permalink to &quot;安裝方式&quot;">​</a></h2><p>透過迅睿CMS插件市場直接安裝</p><h2 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h2><ol><li>安装插件后，在迅睿CMS后台配置 AWS S3 相关信息</li><li>启用插件后，即可在迅睿CMS文件管理中使用 AWS S3 作为存储</li></ol><h2 id="文档站点技術堆疊" tabindex="-1">文档站点技術堆疊 <a class="header-anchor" href="#文档站点技術堆疊" aria-label="Permalink to &quot;文档站点技術堆疊&quot;">​</a></h2><p>本文檔站点基於以下技術構建：</p><p><strong>VitePress</strong> - 靜態網站生成器，版本 ^1.0.0</p><ul><li>官網：<a href="https://vitepress.dev/" target="_blank" rel="noreferrer">https://vitepress.dev/</a></li><li>讀許證證書：MIT License</li></ul><p><strong>vitepress-plugin-image-viewer</strong> - 圖片查看器插件，版本 ^1.1.6</p><ul><li>官網：<a href="https://github.com/noonnightrocker/vitepress-plugin-image-viewer" target="_blank" rel="noreferrer">https://github.com/noonnightrocker/vitepress-plugin-image-viewer</a></li><li>讀許證證書：MIT License</li></ul><h2 id="致謝" tabindex="-1">致謝 <a class="header-anchor" href="#致謝" aria-label="Permalink to &quot;致謝&quot;">​</a></h2><p>感謝 Vue.js、Vite、VitePress 等開放源碼專案的貢獻者。</p><h2 id="作者資訊" tabindex="-1">作者資訊 <a class="header-anchor" href="#作者資訊" aria-label="Permalink to &quot;作者資訊&quot;">​</a></h2><ul><li>作者：陳延德</li><li>郵箱：<a href="mailto:me@chenyande.com" target="_blank" rel="noreferrer">me@chenyande.com</a></li><li>網站：<a href="https://www.chenyande.com" target="_blank" rel="noreferrer">chenyande.com</a></li></ul><h2 id="授權條款" tabindex="-1">授權條款 <a class="header-anchor" href="#授權條款" aria-label="Permalink to &quot;授權條款&quot;">​</a></h2><p>本專案採用 Apache License 2.0 授權</p>',23)])])}const m=a(l,[["render",o]]);export{p as __pageData,m as default};
